fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut nums = nums;
    nums.sort();
    let n = nums.len();
    if n == 0 {
        return 0;
    }
    let mut max_len = 1;
    for i in 0..n {
        let target = nums[i] * k;
        let mut low = i;
        let mut high = n - 1;
        let mut low_search = low;
        let mut high_search = high;
        while low_search <= high_search {
            let mid = (low_search + high_search) / 2;
            if nums[mid] <= target {
                low_search = mid + 1;
            } else {
                high_search = mid - 1;
            }
        }
        let j = low_search - 1;
        let current_len = j - i + 1;
        if current_len > max_len {
            max_len = current_len;
        }
    }
    (n as i64) - max_len as i64
}
